var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"아주 먼 옛날, 한 명의 구도자가 있었다.","JPN":"はるか昔、一人の求道者がいた。","ENG":"Once upon a time, there lived a seeker of truth.","TWN":"很久很久以前，有一位求道者。"},"stage":{"bg":"MAINSTREAM_7010011","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그는 세상을 떠돌며 수많은 사람을 구하고, 그들의 고통을 대신 끌어안았다.","JPN":"彼は世界を周りながら多くの人々を救い、彼らの苦痛を代わりに抱え込んだ。","ENG":"The Seeker traveled the world, saving many lives, bearing their suffering on their behalf.","TWN":"他走遍世界拯救許多的人，替他們承擔痛苦。"},"stage":{"bg":"MAINSTREAM_7010011","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"많은 이들이 구도자를 칭송했고, 그와 함께 고행의 길을 걷고자 했다.","JPN":"多くの人が求道者を称え、彼と共に苦行の道を歩もうとした。","ENG":"Many praised the Seeker and followed him in his path of righteous suffering.","TWN":"求道者因此受到人們的愛戴，並且開始與他一起踏上修行之路。"},"stage":{"bg":"MAINSTREAM_7010011","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 고통은 끝나지 않았다.","JPN":"しかし、苦痛は消えなかった。","ENG":"But the suffering would never end.","TWN":"但痛苦沒有結束。"},"stage":{"bg":"MAINSTREAM_7010010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"전쟁과 병마. 기아와 재난. 핍박과 착취.","JPN":"戦争と病魔。飢餓と災禍。逼迫と搾取。","ENG":"With war and pestilence... famine and disasters... the oppression and the exploitation of the weak...","TWN":"戰爭與兵戎，飢餓與天災，強取與豪奪。"},"stage":{"bg":"MAINSTREAM_7010010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"어디를 가도 그들을 둘러싼 것은 고통이었다.","JPN":"どこへ行っても彼らを取り巻くのは苦痛だった。","ENG":"There was no end to suffering, no matter where they went.","TWN":"無論去到哪裡，等待他們的就只有痛苦。"},"stage":{"bg":"MAINSTREAM_7010010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"구도자는 시들어 갔고, 그를 따르던 이들도 하나씩 떠나갔다.","JPN":"求道者は衰えていき、彼を慕っていた人々も一人ずつ去っていった。","ENG":"The Seeker withered away, and his followers left him one by one.","TWN":"求道者越來越軟弱，原本跟隨著他的人們也一個一個離開。"},"stage":{"bg":"MAINSTREAM_7010011","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"많은 이들이 구도자를 비웃었고, 그의 지친 뒷모습을 손가락질했다.","JPN":"多くの人が求道者を嘲笑し、彼の疲れ果てた後ろ姿に指を差した。","ENG":"Many ridiculed the Seeker, mocking his weary mien.","TWN":"人們開始嘲諷求道者，在他軟弱的背後指指點點。"},"stage":{"bg":"MAINSTREAM_7010011","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"홀로 남은 구도자는, 묵묵히 세상의 끝으로 떠났다.","JPN":"独り残された求道者は、黙々と世界の果てへと旅立った。","ENG":"Alone again, the Seeker quietly set off to the edge of the world.","TWN":"孤單一人的求道者於是默默地走向世界的盡頭。"},"stage":{"bg":"MAINSTREAM_7010011","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"그곳에서 그는 세상의 모든 지식을 알고 있다는 현자와 마주했다.","JPN":"そこで彼は、この世すべての知識を得たという賢者に出会った。","ENG":"There, he met a sage said to possess all the world's knowledge.","TWN":"在那個地方，求道者遇到一位無所不知的智者。"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"구도자는 현자에게 청했다.","JPN":"求道者は賢者に願った。","ENG":"The Seeker pled with the sage.","TWN":"求道者於是向智者請教。"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>위대한 용이 될 방법을 알고 싶소.</color>","JPN":"<color=#ffd34c>偉大なる龍になる方法が知りたい。</color>","ENG":"<color=#ffd34c> I would like to know how to become a great dragon.</color>","TWN":"<color=#ffd34c>我想知道，有什麼方法可以成為偉大的龍。</color>"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"현자는 어째서 용이 되길 원하는지 물었다.","JPN":"賢者はなぜ龍になりたいのか尋ねた。","ENG":"The sage asked the Seeker why.","TWN":"智者問：你為何想成為龍？"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"침묵하던 구도자는 이윽고 고통스러운 표정으로 대답했다.","JPN":"沈黙していた求道者は、やがて苦しそうな表情で答えた。","ENG":"After a brief silence, the Seeker responded with an agonized look on his face.","TWN":"求道者沉默片刻後以痛苦的表情作為回答。"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"세상은 슬픔과 비극이 멈추지 않는 곳이었다.","JPN":"この世は悲しみと悲劇が止まらないところだった。","ENG":"The world as he knew it was full of grief and tragedy.","TWN":"世界是一個充滿痛苦和悲劇的地方。"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"그런 세상을 바꾸고자 그는 세상의 모든 고통을 대신 짊어지려 했다.","JPN":"そんな世界を変えようと、彼はこの世すべての苦痛を代わりに背負おうとした。","ENG":"He sought to bear the suffering of everyone, in order to change the world.","TWN":"他想要透過承擔世人的痛苦來改變世界。"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 모든 것이 끝난 지금, 결국 그는 아무것도 바꾸지 못했다.","JPN":"しかし、すべてが終わった今、結局彼は何も変えられなかった。","ENG":"But now that the endeavor had come to an end, he realized he hadn't changed a thing.","TWN":"結果到頭來卻什麼也沒改變。"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"남은 것은 오직 고통뿐.","JPN":"残ったのは苦痛だけ。","ENG":"The only thing that remained was suffering.","TWN":"留下來的就只有痛苦而已。"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"이제는 그 고통에서나마 벗어나고 싶다.","JPN":"今はその苦痛から解放されたい。","ENG":"He now wanted an escape from that suffering.","TWN":"因此現在的他想要從痛苦中得到解放。"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 구도자 또한 인간이었기에, 스스로 짊어진 고통으로부터 자유로울 수 없었다.","JPN":"しかし彼も所詮ただの人間、、みずから背負った苦痛から自由になることはできなかった。","ENG":"Since the Seeker was only human, he could not free himself from the suffering.","TWN":"但求道者也不過是血肉之軀，無法自己從痛苦中得自由。"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"그러니 인간이 아닌 용이 된다면, 전설로 전해져 내려오는 그 위대한 존재로 거듭난다면…….","JPN":"だから、人間ではない龍になれたら、伝説に伝わるあの偉大な存在に生まれ変われるなら……","ENG":"But if he could become a dragon instead, a great creature of legends...?","TWN":"只要可以成為非血肉之軀的龍，只要能以傳說中的偉大存在之姿重生……"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"이 고통의 굴레에서 해방되어 모든 것을 잊을 수 있으리라.","JPN":"この苦痛の束縛から解放され、すべてを忘れることができるだろう。","ENG":"Then he'd be finally free from all this endless suffering.","TWN":"就可以從痛苦的束縛中得到釋放，忘掉這一切。"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"구도자의 이야기를 들은 현자는 그에게 용의 피를 건네며 말했다.","JPN":"求道者の話を聞いた賢者は、彼に龍の血を渡しながらこう話した。","ENG":"Upon hearing the Seeker's case, the sage handed over the blood of the dragon and spoke.","TWN":"智者聽完求道者的話，便拿出龍血對他說："},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"원한다면 이 피를 마시고 용이 될 수 있다.","JPN":"望むなら、この血を飲んで龍になれる。","ENG":"If you wish, you may drink this blood and become a dragon.","TWN":"只要喝下它就可以成為龍。"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"용은 인간을 벗어난 존재이니, 인간의 고통은 아무런 의미도 없을 것이다.","JPN":"龍は人ならざる存在故、人間の苦痛など何の意味もなさないだろう。","ENG":"As dragons are beings beyond the limits of humans, your human suffering will be rendered meaningless.","TWN":"龍不像人是血肉之軀，那些痛苦對龍而言並沒有意義。"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"허나 고통에서 벗어난다 한들 번뇌에서 자유로운 존재가 있겠는가?","JPN":"しかし、苦痛から解放されたとしても、煩悩から解放される存在なんてあるだろうか？","ENG":"And yet, no being is truly free from their Kleshas, though they may escape suffering.","TWN":"但，就算真的從痛苦中得到解放，煩惱真的會消失嗎？"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"삼라만상에 새로운 것도 사라지는 것도 없으니, 오직 그 형태만이 바뀔 뿐이라.","JPN":"森羅万象新しく生まれるものも、消えて無くなるものもなく、ただその形が変わるのみ。","ENG":"Nothing in this universe is truly destroyed or born anew. It is merely their form that changes.","TWN":"森羅萬象中，一切都是存在的，沒有增加，也沒有消失，不過是型態的改變而已。"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"걸음을 멈춘 자에게 고통은 그저 다른 모습으로 곁에 머물 뿐이다.","JPN":"歩みを止めた者に対して、苦痛は偏に別の姿でそばに留まるだけである。","ENG":"For those who cease to follow the path, suffering will still remain, albeit in a different form.","TWN":"對一個駐足的人而言，痛苦只是以別的形式留在身邊而已。"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"인간이었던 구도자는.","JPN":"人間だった求道者は","ENG":"And thus, the human Seeker...","TWN":"於是，原本是人的求道者，喝下龍血後，"},"stage":{"bg":"MAINSTREAM_7010013","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"그 피를 마시고, 용이 되었다.","JPN":"その血を飲んで、龍となった。","ENG":"...drank the blood to become a dragon.","TWN":"就化身為一尾龍。"},"stage":{"bg":"MAINSTREAM_7010013","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 다시 눈을 떴을 때.","JPN":"そして再び目覚めた時、","ENG":"And when he opened his eyes again...","TWN":"當他再次睜開眼時，"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"자신이 연옥에 떨어졌음을 깨달았다.","JPN":"自分が煉獄に落ちたことに気づいた。","ENG":"...he realized that he had been cast into an inferno.","TWN":"才認清自己已經墜入地獄的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};